/**
 * AddTranslationModal Component - Modal for adding new translation
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { X, Globe, Copy, Palette, FileText } from 'lucide-react';

interface AddTranslationModalProps {
  isOpen: boolean;
  onClose: () => void;
  sourcePageId: string;
  existingLanguages?: string[];
  onSuccess?: () => void;
}

export function AddTranslationModal({
  isOpen,
  onClose,
  sourcePageId,
  existingLanguages = [],
  onSuccess
}: AddTranslationModalProps) {
  const [language, setLanguage] = useState('');
  const [slug, setSlug] = useState('');
  const [copyStructure, setCopyStructure] = useState(true);
  const [copyStyles, setCopyStyles] = useState(true);
  const [copyContent, setCopyContent] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [sourcePageData, setSourcePageData] = useState<any>(null);
  const [copied, setCopied] = useState(false);

  const availableLanguages = [
    { code: 'en', name: 'English', flag: '🇺🇸' },
    { code: 'ar', name: 'Arabic', flag: '🇸🇦' },
    { code: 'tr', name: 'Turkish', flag: '🇹🇷' },
    { code: 'fr', name: 'French', flag: '🇫🇷' },
    { code: 'de', name: 'German', flag: '🇩🇪' },
    { code: 'es', name: 'Spanish', flag: '🇪🇸' }
  ].filter(lang => !existingLanguages.includes(lang.code));

  useEffect(() => {
    if (isOpen && sourcePageId) {
      fetchSourcePage();
      setLanguage('');
      setSlug('');
      setError('');
      setCopyStructure(true);
      setCopyStyles(true);
      setCopyContent(false);
      setCopied(false);
    }
  }, [isOpen, sourcePageId]);

  const fetchSourcePage = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const res = await fetch(`/api/admin/pages/${sourcePageId}/builder`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const result = await res.json();
      if (result.success) {
        setSourcePageData(result.data);
      }
    } catch (err) {
      console.error('Failed to load source page:', err);
    }
  };

  useEffect(() => {
    // تولید خودکار slug از صفحه مبدا
    if (language && sourcePageData) {
      const sourceSlug = sourcePageData.slug || '';
      const slugWithoutLang = sourceSlug.replace(/^\/(en|ar|tr|fr|de|es)\//, '');
      const newSlug = `/${language}/${slugWithoutLang}`;
      setSlug(newSlug);
      console.log('Auto-generated slug:', newSlug);
    }
  }, [language, sourcePageData]);

  const copyPageContent = () => {
    if (!sourcePageData?.builderData) return;

    const textContent: string[] = [];
    
    sourcePageData.builderData.forEach((section: any) => {
      const data = section.data || {};
      
      if (data.title) textContent.push(`Title: ${data.title}`);
      if (data.subtitle) textContent.push(`Subtitle: ${data.subtitle}`);
      if (data.description) textContent.push(`Description: ${data.description}`);
      if (data.content) textContent.push(`Content: ${data.content}`);
      if (data.text) textContent.push(`Text: ${data.text}`);
      
      if (data.primaryButton?.text) textContent.push(`Button: ${data.primaryButton.text}`);
      if (data.secondaryButton?.text) textContent.push(`Button: ${data.secondaryButton.text}`);
      if (data.ctaButton?.text) textContent.push(`Button: ${data.ctaButton.text}`);
      
      ['features', 'items', 'steps', 'benefits', 'cards', 'tabs'].forEach(key => {
        if (Array.isArray(data[key])) {
          data[key].forEach((item: any, idx: number) => {
            if (item.title) textContent.push(`${key}[${idx}].title: ${item.title}`);
            if (item.description) textContent.push(`${key}[${idx}].description: ${item.description}`);
            if (item.text) textContent.push(`${key}[${idx}].text: ${item.text}`);
            if (item.label) textContent.push(`${key}[${idx}].label: ${item.label}`);
          });
        }
      });
      
      textContent.push('---');
    });

    const contentText = textContent.join('\n');
    navigator.clipboard.writeText(contentText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const res = await fetch(`/api/admin/pages/${sourcePageId}/add-translation`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          language,
          slug,
          copyStructure,
          copyStyles,
          copyContent
        })
      });

      const result = await res.json();
      console.log('Translation result:', result);

      if (result.success) {
        onSuccess?.();
        onClose();
      } else {
        setError(result.error || 'Failed to create translation');
      }
    } catch (err: any) {
      setError(err.message || 'Network error. Please try again.');
      console.error('Translation error:', err);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 rounded-lg shadow-xl w-full max-w-md mx-4">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b dark:border-slate-700">
          <div className="flex items-center gap-2">
            <Globe className="text-indigo-600 dark:text-indigo-400" size={24} />
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
              Add Translation
            </h2>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
          >
            <X size={24} />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {/* Copy Page Content Button */}
          {sourcePageData && (
            <div className="p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2 text-sm text-blue-700 dark:text-blue-300">
                  <FileText size={16} />
                  <span>Copy page content for translation</span>
                </div>
                <button
                  type="button"
                  onClick={copyPageContent}
                  className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded transition-colors flex items-center gap-1.5"
                >
                  <Copy size={14} />
                  {copied ? 'Copied!' : 'Copy Content'}
                </button>
              </div>
              <p className="text-xs text-blue-600 dark:text-blue-400 mt-2">
                This will copy all text content from the page so you can translate it easily.
              </p>
            </div>
          )}

          {error && (
            <div className="p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded text-sm text-red-600 dark:text-red-400">
              {error}
            </div>
          )}

          {/* Language Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              New Language *
            </label>
            {availableLanguages.length > 0 ? (
              <div className="grid grid-cols-2 gap-2">
                {availableLanguages.map(lang => (
                  <button
                    key={lang.code}
                    type="button"
                    onClick={() => setLanguage(lang.code)}
                    className={`
                      flex items-center gap-2 p-3 border rounded-lg transition-all
                      ${language === lang.code
                        ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300'
                        : 'border-gray-300 dark:border-gray-600 hover:border-indigo-300 dark:hover:border-indigo-700'
                      }
                    `}
                  >
                    <span className="text-2xl">{lang.flag}</span>
                    <div className="text-left">
                      <div className="font-medium text-sm">{lang.name}</div>
                      <div className="text-xs text-gray-500 dark:text-gray-400">{lang.code.toUpperCase()}</div>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div className="text-sm text-gray-500 dark:text-gray-400 p-3 bg-gray-50 dark:bg-slate-700 rounded">
                All available languages have been added.
              </div>
            )}
          </div>

          {/* Slug */}
          {language && (
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Page Slug *
              </label>
              <input
                type="text"
                value={slug}
                onChange={(e) => setSlug(e.target.value)}
                placeholder={`/${language}/page-name`}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                required
              />
              <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                URL path for this page (e.g., /{language}/about)
              </p>
            </div>
          )}

          {/* Copy Options */}
          {language && (
            <div className="space-y-3 pt-2">
              <div className="text-sm font-medium text-gray-700 dark:text-gray-300">
                Copy Options
              </div>
              
              <label className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={copyStructure}
                  onChange={(e) => setCopyStructure(e.target.checked)}
                  className="mt-1 w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                />
                <div>
                  <div className="flex items-center gap-2 text-sm font-medium text-gray-900 dark:text-white">
                    <Copy size={14} />
                    Copy page structure
                  </div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                    Copy section types and order (content will be empty)
                  </p>
                </div>
              </label>

              <label className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={copyStyles}
                  onChange={(e) => setCopyStyles(e.target.checked)}
                  className="mt-1 w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                  disabled={!copyStructure}
                />
                <div>
                  <div className="flex items-center gap-2 text-sm font-medium text-gray-900 dark:text-white">
                    <Palette size={14} />
                    Copy style settings
                  </div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                    Copy colors, spacing, and layout settings
                  </p>
                </div>
              </label>

              <label className="flex items-start gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={copyContent}
                  onChange={(e) => setCopyContent(e.target.checked)}
                  className="mt-1 w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                  disabled={!copyStructure}
                />
                <div>
                  <div className="flex items-center gap-2 text-sm font-medium text-gray-900 dark:text-white">
                    <FileText size={14} />
                    Copy content (text will need translation)
                  </div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                    Copy all text content - you can edit and translate it later
                  </p>
                </div>
              </label>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!language || !slug || loading}
              className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {loading ? 'Creating...' : 'Create Translation'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
